  1→import React, { useState } from 'react';
  2→import { User, SMCContent } from '../types';
  3→import { smcService } from '../services/smc';
  4→import { ArrowLeft, FileText, HelpCircle, PenTool, Sparkles, Copy, Download, Check, Loader2, Layout, MessageSquare, BookOpen, Library, Clock, AlignLeft, Link as LinkIcon, Bot, Archive, ChevronRight, Award, Globe, ArrowRight, Eye } from 'lucide-react';
  5→
  6→interface Props {
  7→  onBack: () => void;
  8→  user: User | null;
  9→  onDeductCredits: (amount: number) => boolean;
 10→  library: SMCContent[];
 11→  onAddToLibrary: (item: SMCContent) => void;
 12→  onNavigateToPublisher?: (data: { topic: string, url: string, brief: string }) => void;
 13→  onNavigateToDirectory?: () => void;
 14→}
 15→
 16→type ToolType = 'home' | 'fiche' | 'faq' | 'article';
 17→type Tab = 'studio' | 'library';
 18→
 19→const SMCStudio: React.FC<Props> = ({ onBack, user, onDeductCredits, library, onAddToLibrary, onNavigateToPublisher, onNavigateToDirectory }) => {
 20→  const [activeTab, setActiveTab] = useState<Tab>('studio');
 21→  const [currentTool, setCurrentTool] = useState<ToolType>('home');
 22→  const [result, setResult] = useState('');
 23→  const [isGenerating, setIsGenerating] = useState(false);
 24→  const [copied, setCopied] = useState(false);
 25→
 26→  // --- States pour l'outil Article (Flux Blog Optimizer) ---
 27→  const [articleStep, setArticleStep] = useState<'brief' | 'writing' | 'done'>('brief');
 28→  const [briefContent, setBriefContent] = useState('');
 29→  
 30→  // Form States
 31→  const [ficheData, setFicheData] = useState({ name: '', features: '' });
 32→  const [faqData, setFaqData] = useState({ topic: '', context: '' });
 33→  const [articleData, setArticleData] = useState({ title: '', url: '', tone: 'Professionnel' }); // URL & Tone used for Brief gen
 34→
 35→  const COSTS = {
 36→    fiche: 1,
 37→    faq: 1,
 38→    brief: 1, // Brief d'article
 39→    article: 3 // Rédaction complète
 40→  };
 41→
 42→  const handleCopy = (content: string) => {
 43→    navigator.clipboard.writeText(content);
 44→    setCopied(true);
 45→    setTimeout(() => setCopied(false), 2000);
 46→  };
 47→
 48→  const handleDownload = (filename: string, content: string) => {
 49→    const blob = new Blob([content], { type: 'text/markdown' });
 50→    const url = URL.createObjectURL(blob);
 51→    const a = document.createElement('a');
 52→    a.href = url;
 53→    a.download = filename;
 54→    document.body.appendChild(a);
 55→    a.click();
 56→    document.body.removeChild(a);
 57→    URL.revokeObjectURL(url);
 58→  };
 59→
 60→  const handleNavigateToPublisherAction = () => {
 61→    if (onNavigateToPublisher) {
 62→        onNavigateToPublisher({
 63→            topic: articleData.title,
 64→            url: articleData.url,
 65→            brief: briefContent // Le PublisherRequest se base sur le brief
 66→        });
 67→    }
 68→  };
 69→
 70→  const handleRestoreFromLibrary = (item: SMCContent) => {
 71→    // 1. Déterminer l'outil
 72→    let tool: ToolType = 'home';
 73→    if (item.type === 'fiche') tool = 'fiche';
 74→    else if (item.type === 'faq') tool = 'faq';
 75→    else if (item.type === 'article' || item.type === 'brief') tool = 'article';
 76→
 77→    setCurrentTool(tool);
 78→
 79→    // 2. Restaurer le contenu et l'état
 80→    if (item.type === 'article') {
 81→        setResult(item.content);
 82→        setArticleStep('done');
 83→        // Tentative de récupération du titre depuis "Article: Titre - Date"
 84→        const titleClean = item.title.split(' - ')[0].replace('Article: ', '').trim();
 85→        setArticleData(prev => ({ ...prev, title: titleClean }));
 86→        // Si possible, on pourrait essayer de retrouver le brief parent via meta, mais ici on affiche juste le résultat
 87→    } else if (item.type === 'brief') {
 88→        setBriefContent(item.content);
 89→        setArticleStep('writing');
 90→        const titleClean = item.title.split(' - ')[0].replace('Brief: ', '').trim();
 91→        setArticleData(prev => ({ ...prev, title: titleClean }));
 92→    } else {
 93→        setResult(item.content);
 94→        // Restauration contextuelle basique pour les formulaires
 95→        if (item.type === 'fiche') {
 96→             const nameClean = item.title.split(' - ')[0].replace('Fiche: ', '').trim();
 97→             setFicheData(prev => ({ ...prev, name: nameClean }));
 98→        }
 99→        if (item.type === 'faq') {
100→             const topicClean = item.title.split(' - ')[0].replace('FAQ: ', '').trim();
101→             setFaqData(prev => ({ ...prev, topic: topicClean }));
102→        }
103→    }
104→
105→    // 3. Basculer vers l'onglet Studio
106→    setActiveTab('studio');
107→  };
108→
109→  // Generic generator for simple tools (Fiche, FAQ)
110→  const runSimpleGeneration = async (type: 'fiche' | 'faq', cost: number, generator: () => Promise<string>, titlePrefix: string) => {
111→    if (onDeductCredits(cost)) {
112→      setIsGenerating(true);
113→      setResult('');
114→      try {
115→        const content = await generator();
116→        setResult(content);
117→        
118→        // Save to Library
119→        const newItem: SMCContent = {
120→            id: `smc_${Date.now()}`,
121→            type,
122→            title: `${titlePrefix} - ${new Date().toLocaleTimeString()}`,
123→            content,
124→            timestamp: new Date().toISOString()
125→        };
126→        onAddToLibrary(newItem);
127→
128→      } catch (e) {
129→        console.error(e);
130→        alert("Une erreur est survenue.");
131→      } finally {
132→        setIsGenerating(false);
133→      }
134→    }
135→  };
136→
137→  // --- Article Generation Logic (2 Steps) ---
138→
139→  const handleGenerateBrief = async () => {
140→    if (!articleData.title && !articleData.url) {
141→        alert("Sujet ou URL requis.");
142→        return;
143→    }
144→
145→    if (onDeductCredits(COSTS.brief)) {
146→        setIsGenerating(true);
147→        try {
148→            const brief = await smcService.generateBrief(articleData.title, articleData.url);
149→            setBriefContent(brief);
150→            setArticleStep('writing'); // Move to step 2
151→            
152→            // Save Brief to Library
153→            onAddToLibrary({
154→                id: `brief_${Date.now()}`,
155→                type: 'brief',
156→                title: `Brief: ${articleData.title || 'Architecture Article'}`,
157→                content: brief,
158→                timestamp: new Date().toISOString()
159→            });
160→
161→        } catch (e) {
162→            console.error(e);
163→            alert("Erreur lors du brief.");
164→        } finally {
165→            setIsGenerating(false);
166→        }
167→    }
168→  };
169→
170→  const handleWriteFullArticle = async () => {
171→    if (onDeductCredits(COSTS.article)) {
172→        setIsGenerating(true);
173→        try {
174→            const article = await smcService.generateFullArticle(briefContent, articleData.title);
175→            setResult(article);
176→            setArticleStep('done'); // Move to step 3
177→
178→            // Save Article to Library
179→            onAddToLibrary({
180→                id: `art_${Date.now()}`,
181→                type: 'article',
182→                title: `Article: ${articleData.title || 'Rédaction Complète'}`,
183→                content: article,
184→                timestamp: new Date().toISOString(),
185→                meta: { briefId: `brief_${Date.now()}` } // Link to brief loosely
186→            });
187→
188→        } catch (e) {
189→            console.error(e);
190→            alert("Erreur lors de la rédaction.");
191→        } finally {
192→            setIsGenerating(false);
193→        }
194→    }
195→  };
196→
197→  const renderHome = () => (
198→    <div className="space-y-8 animate-in fade-in duration-500">
199→      <div className="text-center space-y-4">
200→        <h1 className="text-4xl font-serif font-bold text-white">SMC Studio</h1>
201→        <p className="text-gray-400 max-w-xl mx-auto">
202→          Smart Marketing Content : Votre usine de production de contenu optimisé pour les Answer Engines.
203→        </p>
204→      </div>
205→
206→      <div className="grid md:grid-cols-3 gap-6 max-w-5xl mx-auto">
207→        {/* Card Fiche */}
208→        <button 
209→          onClick={() => setCurrentTool('fiche')}
210→          className="glass-panel p-8 rounded-2xl border border-white/10 hover:border-blue-500/50 hover:bg-blue-500/5 transition-all group text-left relative overflow-hidden"
211→        >
212→          <div className="absolute top-0 right-0 p-4 opacity-5 group-hover:opacity-10 transition-opacity">
213→            <Layout size={80} />
214→          </div>
215→          <div className="w-12 h-12 rounded-xl bg-blue-500/20 flex items-center justify-center text-blue-400 mb-6 group-hover:scale-110 transition-transform">
216→            <FileText size={24} />
217→          </div>
218→          <h3 className="text-xl font-bold text-white mb-2">Fiche Produit</h3>
219→          <p className="text-sm text-gray-400 mb-6">Générez des fiches techniques structurées et vendeuses.</p>
220→          <div className="inline-flex items-center gap-1.5 px-3 py-1 rounded-full bg-blue-500/10 text-blue-400 text-xs font-bold border border-blue-500/20">
221→            <Sparkles size={10} /> 1 Crédit
222→          </div>
223→        </button>
224→
225→        {/* Card FAQ */}
226→        <button 
227→          onClick={() => setCurrentTool('faq')}
228→          className="glass-panel p-8 rounded-2xl border border-white/10 hover:border-purple-500/50 hover:bg-purple-500/5 transition-all group text-left relative overflow-hidden"
229→        >
230→          <div className="absolute top-0 right-0 p-4 opacity-5 group-hover:opacity-10 transition-opacity">
231→            <MessageSquare size={80} />
232→          </div>
233→          <div className="w-12 h-12 rounded-xl bg-purple-500/20 flex items-center justify-center text-purple-400 mb-6 group-hover:scale-110 transition-transform">
234→            <HelpCircle size={24} />
235→          </div>
236→          <h3 className="text-xl font-bold text-white mb-2">Générateur FAQ</h3>
237→          <p className="text-sm text-gray-400 mb-6">Créez des questions/réponses pertinentes pour rassurer vos clients.</p>
238→          <div className="inline-flex items-center gap-1.5 px-3 py-1 rounded-full bg-purple-500/10 text-purple-400 text-xs font-bold border border-purple-500/20">
239→            <Sparkles size={10} /> 1 Crédit
240→          </div>
241→        </button>
242→
243→        {/* Card Article */}
244→        <button 
245→          onClick={() => setCurrentTool('article')}
246→          className="glass-panel p-8 rounded-2xl border border-white/10 hover:border-purple-500/50 hover:bg-purple-500/5 transition-all group text-left relative overflow-hidden"
247→        >
248→          <div className="absolute top-0 right-0 p-4 opacity-5 group-hover:opacity-10 transition-opacity">
249→            <BookOpen size={80} />
250→          </div>
251→          <div className="w-12 h-12 rounded-xl bg-purple-500/20 flex items-center justify-center text-purple-400 mb-6 group-hover:scale-110 transition-transform">
252→            <PenTool size={24} />
253→          </div>
254→          <h3 className="text-xl font-bold text-white mb-2">Rédaction Article</h3>
255→          <p className="text-sm text-gray-400 mb-6">Workflow complet : Architecture (Brief) puis Rédaction AEO.</p>
256→          <div className="inline-flex items-center gap-1.5 px-3 py-1 rounded-full bg-purple-500/10 text-purple-400 text-xs font-bold border border-purple-500/20">
257→            <Sparkles size={10} /> 1 + 3 Crédits
258→          </div>
259→        </button>
260→      </div>
261→    </div>
262→  );
263→
264→  const renderToolArchives = (tool: ToolType) => {
265→    const archives = library.filter(item => {
266→        if (tool === 'article') return item.type === 'article' || item.type === 'brief';
267→        return item.type === tool;
268→    });
269→
270→    if (archives.length === 0) return null;
271→
272→    return (
273→        <div className="border-t border-white/10 pt-10 animate-in fade-in slide-in-from-bottom-8">
274→            <div className="flex items-center justify-between mb-6">
275→                <h3 className="text-xl font-serif font-bold text-white flex items-center gap-2">
276→                    <Archive size={20} className="text-gray-400" /> 
277→                    Archives {tool === 'fiche' ? 'Fiches Produits' : tool === 'faq' ? 'FAQs' : 'Articles & Briefs'}
278→                </h3>
279→                <span className="text-xs text-gray-500 bg-purple-500/5 px-2 py-1 rounded-full">{archives.length} fichiers</span>
280→            </div>
281→
282→            <div className="grid md:grid-cols-3 gap-6">
283→                {archives.map((item) => (
284→                    <div key={item.id} className="glass-panel p-5 rounded-xl border border-white/10 hover:border-primary/30 transition-all group flex flex-col">
285→                        <div className="flex justify-between items-start mb-3">
286→                            <span className={`text-[10px] font-bold px-2 py-1 rounded uppercase tracking-wider 
287→                                ${item.type === 'article' ? 'bg-purple-400/10 text-purple-300 border border-purple-400/20' : 
288→                                  item.type === 'brief' ? 'bg-purple-500/10 text-purple-400 border border-purple-500/20' : 
289→                                  'bg-blue-500/10 text-blue-400 border border-blue-500/20'}`}>
290→                                {item.type.toUpperCase()}
291→                            </span>
292→                            <span className="text-xs text-gray-500 flex items-center gap-1">
293→                                <Clock size={10} /> {new Date(item.timestamp).toLocaleDateString()}
294→                            </span>
295→                        </div>
296→                        
297→                        <h4 className="font-bold text-white mb-2 line-clamp-2 min-h-[3rem] text-sm">{item.title}</h4>
298→                        
299→                        <div className="bg-[#050208] p-3 rounded border border-white/5 mb-4 flex-1 overflow-hidden relative h-24">
300→                            <p className="text-[10px] text-gray-500 font-mono line-clamp-4 leading-relaxed">{item.content}</p>
301→                            <div className="absolute bottom-0 left-0 w-full h-8 bg-gradient-to-t from-[#050208] to-transparent"></div>
302→                        </div>
303→
304→                        <div className="flex gap-2 pt-2 border-t border-white/5">
305→                            <button 
306→                                onClick={() => handleRestoreFromLibrary(item)}
307→                                className="flex-1 py-1.5 bg-primary/10 hover:bg-primary/20 rounded text-[10px] font-bold text-primary transition-colors flex items-center justify-center gap-1"
308→                            >
309→                                <Eye size={10} /> Ouvrir
310→                            </button>
311→                            <button 
312→                                onClick={() => handleCopy(item.content)}
313→                                className="flex-1 py-1.5 bg-purple-500/5 hover:bg-white/10 rounded text-[10px] font-medium text-gray-300 transition-colors flex items-center justify-center gap-1"
314→                            >
315→                                <Copy size={10} /> Copier
316→                            </button>
317→                        </div>
318→                    </div>
319→                ))}
320→            </div>
321→        </div>
322→    );
323→  };
324→
325→  const renderTool = () => {
326→    let title = '', color = '', icon = null;
327→    
328→    switch(currentTool) {
329→      case 'fiche': title = 'Fiche Produit'; color = 'text-blue-400'; icon = <FileText />; break;
330→      case 'faq': title = 'Générateur FAQ'; color = 'text-purple-400'; icon = <HelpCircle />; break;
331→      case 'article': title = 'Rédaction Article'; color = 'text-purple-400'; icon = <PenTool />; break;
332→    }
333→
334→    // Contenu à afficher dans la fenêtre de droite
335→    const displayContent = currentTool === 'article' 
336→        ? (articleStep === 'done' ? result : briefContent) 
337→        : result;
338→
339→    return (
340→      <div className="flex flex-col gap-12 animate-in slide-in-from-right duration-300">
341→        <div className="grid lg:grid-cols-12 gap-8 h-full min-h-[600px]">
342→          
343→          {/* Left: Input Form */}
344→          <div className="lg:col-span-4 space-y-6">
345→            <div className="glass-panel p-6 rounded-xl border border-white/10">
346→              <div className="flex items-center gap-3 mb-6">
347→                <div className={`p-2 rounded-lg bg-purple-500/5 ${color}`}>{icon}</div>
348→                <h2 className="text-xl font-bold text-white">{title}</h2>
349→              </div>
350→
351→              {currentTool === 'fiche' && (
352→                <div className="space-y-4">
353→                  <div>
354→                    <label className="text-sm text-gray-400 block mb-2">Nom du produit / service</label>
355→                    <input 
356→                      type="text" 
357→                      className="w-full bg-black/40 border border-white/10 rounded-lg p-3 text-white focus:border-blue-500/50 outline-none"
358→                      placeholder="Ex: SuperVacuum 3000"
359→                      value={ficheData.name}
360→                      onChange={(e) => setFicheData({...ficheData, name: e.target.value})}
361→                    />
