  1→import React, { useState, useEffect } from 'react';
  2→import { AnalysisResult, User, SMCContent } from '../types';
  3→import { generateJsonLd, SchemaInput } from '../services/schema_service';
  4→import { ArrowLeft, Code, Download, Copy, Check, ShieldCheck, Globe, Share2, Building2, Phone, Mail, Image as ImageIcon, ExternalLink, RefreshCw, Zap, Archive, Eye } from 'lucide-react';
  5→
  6→interface Props {
  7→  onBack: () => void;
  8→  history: AnalysisResult[];
  9→  user: User | null;
 10→  onDeductCredits: (amount: number) => boolean;
 11→  savedFiles: SMCContent[];
 12→  onSaveFile: (item: SMCContent) => void;
 13→}
 14→
 15→const SchemaOrg: React.FC<Props> = ({ onBack, history, user, onDeductCredits, savedFiles, onSaveFile }) => {
 16→  const [copied, setCopied] = useState(false);
 17→  const [formData, setFormData] = useState<SchemaInput>({
 18→    name: '',
 19→    url: '',
 20→    logoUrl: '',
 21→    description: '',
 22→    socialProfiles: ['', '', ''],
 23→    contactPhone: '',
 24→    contactEmail: '',
 25→    alternateName: ''
 26→  });
 27→  
 28→  const [jsonOutput, setJsonOutput] = useState('');
 29→  const [isGenerated, setIsGenerated] = useState(false);
 30→
 31→  // Pré-remplissage basé sur l'historique
 32→  useEffect(() => {
 33→    if (history.length > 0) {
 34→      const latest = history[0];
 35→      const urlObj = new URL(latest.url);
 36→      const hostname = urlObj.hostname;
 37→      const name = hostname.replace('www.', '').split('.')[0];
 38→      const formattedName = name.charAt(0).toUpperCase() + name.slice(1);
 39→
 40→      setFormData(prev => ({
 41→        ...prev,
 42→        name: formattedName,
 43→        url: urlObj.origin,
 44→        logoUrl: `${urlObj.origin}/logo.png`,
 45→        description: `Site officiel de ${formattedName}.`,
 46→        contactEmail: `contact@${hostname}`
 47→      }));
 48→    }
 49→  }, [history]);
 50→
 51→  // Régénération automatique à chaque changement du formulaire
 52→  useEffect(() => {
 53→    if (isGenerated) {
 54→        setJsonOutput(generateJsonLd(formData));
 55→    }
 56→  }, [formData, isGenerated]);
 57→
 58→  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
 59→    setFormData({ ...formData, [e.target.name]: e.target.value });
 60→  };
 61→
 62→  const handleSocialChange = (index: number, value: string) => {
 63→    const newSocials = [...formData.socialProfiles];
 64→    newSocials[index] = value;
 65→    setFormData({ ...formData, socialProfiles: newSocials });
 66→  };
 67→
 68→  const handleGenerate = () => {
 69→    if (onDeductCredits(5)) {
 70→        const output = generateJsonLd(formData);
 71→        setJsonOutput(output);
 72→        setIsGenerated(true);
 73→        
 74→        // Sauvegarde dans l'historique
 75→        onSaveFile({
 76→            id: `schema_${Date.now()}`,
 77→            type: 'fiche', // Using Generic type
 78→            title: `Schema Organization - ${formData.name}`,
 79→            content: output,
 80→            timestamp: new Date().toISOString()
 81→        });
 82→    }
 83→  };
 84→
 85→  const handleCopy = (content?: string) => {
 86→    navigator.clipboard.writeText(content || jsonOutput);
 87→    setCopied(true);
 88→    setTimeout(() => setCopied(false), 2000);
 89→  };
 90→
 91→  const handleDownload = (filename?: string, content?: string) => {
 92→    const blob = new Blob([content || jsonOutput], { type: 'application/ld+json' });
 93→    const url = URL.createObjectURL(blob);
 94→    const a = document.createElement('a');
 95→    a.href = url;
 96→    a.download = filename || 'schema.jsonld';
 97→    document.body.appendChild(a);
 98→    a.click();
 99→    document.body.removeChild(a);
100→    URL.revokeObjectURL(url);
101→  };
102→
103→  const handleRestore = (content: string) => {
104→      // Pour une restauration complète, il faudrait parser le JSON pour remplir le formulaire
105→      // Ici on restaure juste le code de sortie pour la visualisation
106→      setJsonOutput(content);
107→      setIsGenerated(true);
108→      window.scrollTo({ top: 0, behavior: 'smooth' });
109→  };
110→
111→  return (
