 91→    const url = URL.createObjectURL(blob);
 92→    const a = document.createElement('a');
 93→    a.href = url;
 94→    a.download = filename || 'robots.txt';
 95→    document.body.appendChild(a);
 96→    a.click();
 97→    document.body.removeChild(a);
 98→    URL.revokeObjectURL(url);
 99→  };
100→
101→  const handleCopy = (content?: string) => {
102→    navigator.clipboard.writeText(content || optimizedContent);
103→    setCopied(true);
104→    setTimeout(() => setCopied(false), 2000);
105→  };
106→
107→  const getImplementationSteps = (platform: string) => {
108→    if (platform.includes('WordPress')) {
109→      return {
110→        title: "Installation sur WordPress",
111→        icon: <Settings size={20} />,
