115→          "Si vous utilisez RankMath : Allez dans 'Rank Math' → 'Réglages généraux' → 'Modifier robots.txt'.",
116→          "Si aucun plugin SEO : Utilisez un plugin 'File Manager' ou un accès FTP.",
117→          "Copiez le code généré ci-dessus et remplacez tout le contenu existant.",
118→          "Sauvegardez les modifications."
119→        ]
120→      };
121→    }
122→    if (platform.includes('Shopify')) {
123→      return {
124→        title: "Installation sur Shopify",
125→        icon: <FileJson size={20} />,
126→        steps: [
127→          "Depuis votre admin Shopify, allez dans 'Boutique en ligne' → 'Thèmes'.",
128→          "Cliquez sur le bouton 'Actions' (ou les trois points) → 'Modifier le code'.",
129→          "Dans la barre de recherche de fichiers, tapez 'robots'.",
130→          "Cliquez sur 'Ajouter un nouveau modèle' → sélectionnez 'robots.txt' si robots.txt.liquid n'existe pas.",
131→          "Collez le code optimisé dans le fichier.",
132→          "Cliquez sur 'Enregistrer' en haut à droite."
133→        ]
134→      };
135→    }
136→    if (platform.includes('SaaS') || platform.includes('App')) {
